# ------------------------------------------------------------
# LANGUAGE DETECTION
# ------------------------------------------------------------
function Get-Lang {
    try { $uiLang = (Get-UICulture).TwoLetterISOLanguageName }
    catch { $uiLang = "en" }
    $supported = @("it","ru","zh","de","es","fr","pt","tr","pl")
    if ($supported -contains $uiLang) { return $uiLang }
    return "en"
}

