# ------------------------------------------------------------
# EDITION DETECTION
# Fix: aggiunto IoTEnterpriseS e pattern esteso per LTSC
# ------------------------------------------------------------
function Get-WinEdition {
    $caption = (Get-CimInstance Win32_OperatingSystem -ErrorAction SilentlyContinue).Caption
    $build   = (Get-CimInstance Win32_OperatingSystem -ErrorAction SilentlyContinue).BuildNumber
    try {
        $ed = (Get-WindowsEdition -Online -ErrorAction SilentlyContinue).Edition
    } catch { $ed = $null }
    if (-not $ed) {
        if ($caption -match "LTSC|IoT")  { $ed = "IoTEnterpriseS" }
        elseif ($caption -match "Pro")   { $ed = "Professional" }
        elseif ($caption -match "Home")  { $ed = "Core" }
        else                             { $ed = "Unknown" }
    }
    return @{ Edition = $ed; Caption = $caption; Build = $build }
}

function Get-SuggestedOption {
    param([string]$Edition)
    # Fix: pattern esteso per coprire IoTEnterpriseS, EnterpriseS, LTSC
    if ($Edition -match "IoTEnterprise|EnterpriseS|LTSC|IoT") { return "3" }
    if ($Edition -match "Professional|Pro")                    { return "2" }
    if ($Edition -match "Core|Home")                           { return "1" }
    return $null
}

# ------------------------------------------------------------
# MENU
# ------------------------------------------------------------
function Show-Menu {
    param([hashtable]$WinInfo, [string]$Suggested)
    Clear-Host
    Write-Host ""
    Write-Host "  +-----------------------------------------------+" -ForegroundColor Cyan
    Write-Host ("  |  {0,-45}|" -f $S.Title)    -ForegroundColor Cyan
    Write-Host ("  |  {0,-45}|" -f $S.Subtitle) -ForegroundColor DarkCyan
    Write-Host "  +-----------------------------------------------+" -ForegroundColor Cyan
    Write-Host ""
    Write-Host ("  {0}: {1} ({2} {3})" -f $S.Detected, $WinInfo.Caption, $S.Build, $WinInfo.Build) -ForegroundColor Gray
    Write-Host ""
    Write-Host "  $($S.SelectModule)" -ForegroundColor White
    Write-Host ""

    $options = @{
        "1" = "Win11 Home"
        "2" = "Win11 Pro"
        "3" = "Win11 IoT LTSC 24H2"
        "4" = "Adobe Workstation"
    }

    foreach ($key in "1","2","3","4") {
        if ($key -eq $Suggested) {
            Write-Host ("    [{0}]  {1}  {2}" -f $key, $options[$key], $S.Recommended) -ForegroundColor Green
        } elseif ($key -eq "4") {
            Write-Host ("    [{0}]  {1}" -f $key, $options[$key]) -ForegroundColor Yellow
        } else {
            Write-Host ("    [{0}]  {1}" -f $key, $options[$key]) -ForegroundColor White
        }
    }

    Write-Host ""
    Write-Host ("    [0]  {0}" -f $S.Exit) -ForegroundColor Gray
    Write-Host ""
    Write-Host "  +-----------------------------------------------+" -ForegroundColor Cyan
    Write-Host ""
}

# ------------------------------------------------------------
# EXTRACT POWERRUN
# ------------------------------------------------------------
function Extract-PowerRun {
    $WorkDir = "$env:TEMP\Titanium"
    $PRExe   = "$WorkDir\PowerRun.exe"
    if (!(Test-Path $WorkDir)) { New-Item -Path $WorkDir -ItemType Directory -Force | Out-Null }
    try {
        [IO.File]::WriteAllBytes($PRExe, [Convert]::FromBase64String($_PRB64))
        return $PRExe
    } catch {
        Write-Host ("  {0} {1}" -f $S.PRError, $_) -ForegroundColor Red
        return $null
    }
}

# ------------------------------------------------------------
# LAUNCH AS SYSTEM
# Flusso corretto:
# 1. Menu gira come utente normale (irm | iex)
# 2. Utente sceglie il modulo
# 3. PowerRun estratto in %TEMP%
# 4. PowerRun apre NUOVA finestra PowerShell come SYSTEM
# 5. Nuova finestra SYSTEM scarica ed esegue il modulo scelto
# ------------------------------------------------------------
function Launch-AsSystem {
    param([string]$ScriptUrl, [string]$Label)
    Write-Host ""
    Write-Host "  $($S.Preparing)" -ForegroundColor Cyan

    $PRExe = Extract-PowerRun
    if (-not $PRExe) { Pause; return }

    Write-Host "  $($S.PRReady)"          -ForegroundColor Green
    Write-Host "  $($S.Launching) $Label" -ForegroundColor Cyan
    Write-Host "  $($S.RunningSystem)"    -ForegroundColor Yellow
    Write-Host ""

    $PS = "$env:SystemRoot\System32\WindowsPowerShell\v1.0\powershell.exe"

    # Codifica il comando in base64 Unicode per evitare problemi
    # di escaping virgolette su LTSC e varianti N/SN
    $innerCmd  = "iex ((New-Object System.Net.WebClient).DownloadString('$ScriptUrl'))"
    $encodedCmd = [Convert]::ToBase64String(
        [Text.Encoding]::Unicode.GetBytes($innerCmd)
    )

    Start-Process -FilePath $PRExe `
        -ArgumentList "`"$PS`" -NoProfile -ExecutionPolicy Bypass -EncodedCommand $encodedCmd" `
        -Wait

    # Cleanup dopo che la sessione SYSTEM e' terminata
    Start-Sleep -Seconds 2
    Remove-Item -Path $PRExe -Force -ErrorAction SilentlyContinue
    Write-Host "  $($S.CleanupDone)" -ForegroundColor Gray
}

# ------------------------------------------------------------
# WRONG EDITION WARNING
# ------------------------------------------------------------
function Confirm-WrongEdition {
    param([string]$Chosen, [string]$Suggested, [string]$ChosenLabel, [string]$SuggestedLabel)
    Write-Host ""
    Write-Host "  +-----------------------------------------------+" -ForegroundColor Yellow
    Write-Host ("  |  {0,-45}|" -f $S.WarnTitle) -ForegroundColor Yellow
    Write-Host "  +-----------------------------------------------+" -ForegroundColor Yellow
    Write-Host ""
    Write-Host ("  {0} [{1}] {2}" -f $S.WarnSelected, $Chosen,    $ChosenLabel)    -ForegroundColor White
    Write-Host ("  {0} [{1}] {2}" -f $S.WarnDetected, $Suggested, $SuggestedLabel) -ForegroundColor Cyan
    Write-Host ""
    Write-Host "  $($S.WarnRisk)" -ForegroundColor Yellow
    Write-Host ""
    Write-Host ("  " + ($S.WarnPressRec  -f $Suggested)) -ForegroundColor Green
    Write-Host ("  " + ($S.WarnPressCont -f $Chosen))    -ForegroundColor White
    Write-Host "  $($S.WarnPressBack)"                   -ForegroundColor Gray
    Write-Host ""
    return (Read-Host "  $($S.YourChoice)")
}

# ------------------------------------------------------------
# MAIN
# ------------------------------------------------------------
$Base = "https://dedo-os.dedonato-paolo.workers.dev"

$Scripts = @{
    "1" = @{ Url = "$Base/home";  Label = "Win11 Home" }
    "2" = @{ Url = "$Base/pro";   Label = "Win11 Pro" }
    "3" = @{ Url = "$Base/ltsc";  Label = "Win11 IoT LTSC 24H2" }
    "4" = @{ Url = "$Base/adobe"; Label = "Adobe Workstation" }
}

# Rileva edizione e lingua una volta sola all'avvio
$WinInfo   = Get-WinEdition
$Suggested = Get-SuggestedOption -Edition $WinInfo.Edition

do {
    Show-Menu -WinInfo $WinInfo -Suggested $Suggested
    $choice = Read-Host "  $($S.YourChoice)"

    if ($choice -eq "0") {
        Write-Host ""
        Write-Host "  $($S.Bye)" -ForegroundColor Gray
        exit 0
    }

    if (-not $Scripts.ContainsKey($choice)) {
        Write-Host ""
        Write-Host "  $($S.InvalidOption)" -ForegroundColor Yellow
        Start-Sleep -Seconds 1
        continue
    }

    # Avviso se edizione sbagliata (Adobe [4] sempre valido su qualsiasi edizione)
    if ($Suggested -and $choice -ne $Suggested -and $choice -ne "4") {
        $confirm = Confirm-WrongEdition `
            -Chosen          $choice `
            -Suggested       $Suggested `
            -ChosenLabel     $Scripts[$choice].Label `
            -SuggestedLabel  $Scripts[$Suggested].Label

        if ($confirm -eq "0")            { continue }
        elseif ($confirm -eq $Suggested) { $choice = $Suggested }
        elseif ($confirm -ne $choice)    { continue }
    }

    $selected = $Scripts[$choice]
    Launch-AsSystem -ScriptUrl $selected.Url -Label $selected.Label

} while ($true)
